import { useEffect } from 'react';

function useTitulo(titulo) {
  useEffect(() => {
    document.title = titulo;
  }, [titulo]);
}

// Use
function Pagina() {
  useTitulo('DevEstudos - Home');
  return <h1>Home</h1>;
}

